void quicksort(int[] z, int lo, int hi) {
    if (lo >= hi) return;              // Basisfall: 0 oder 1 Element
    int pivot = z[hi];
    int i = lo - 1;
    for (int j = lo; j < hi; j++) {
        if (z[j] < pivot) { i++; tausche(z, i, j); }
    }
    tausche(z, i + 1, hi);
    int p = i + 1;                     // Position des Pivots nach dem Partitionieren
    quicksort(z, lo, p - 1);           // rekursiv: linke Hälfte
    quicksort(z, p + 1, hi);           // rekursiv: rechte Hälfte
}

int[] mergeSort(int[] z) {
    if (z.length <= 1) return z;                    // Basisfall
    int mitte = z.length / 2;
    int[] links  = mergeSort(Arrays.copyOfRange(z, 0, mitte));
    int[] rechts = mergeSort(Arrays.copyOfRange(z, mitte, z.length));
    return verschmelzen(links, rechts);
}

int[] verschmelzen(int[] links, int[] rechts) {
    int[] ergebnis = new int[links.length + rechts.length];
    int i = 0, j = 0, k = 0;
    while (i < links.length && j < rechts.length) {
        ergebnis[k++] = (links[i] <= rechts[j]) ? links[i++] : rechts[j++];
    }
    while (i < links.length)  ergebnis[k++] = links[i++];   // Reste anhängen
    while (j < rechts.length) ergebnis[k++] = rechts[j++];
    return ergebnis;
}

