class Stapel {
    private Knoten oben;   // zeigt immer auf das zuletzt eingefügte Element

    void push(int wert) {
        Knoten neu = new Knoten(wert);
        neu.next = oben;   // neuer Knoten zeigt auf den alten obersten
        oben = neu;         // und wird selbst zum neuen obersten
    }

    int pop() {
        int wert = oben.wert;
        oben = oben.next;   // der zweite wird zum neuen obersten
        return wert;
    }

    boolean istLeer() { return oben == null; }
}

