void hanoi(int n, char von, char hilfe, char nach) {
    if (n == 0) return;                    // Basisfall: nichts zu tun
    hanoi(n - 1, von, nach, hilfe);         // 1. kleinere Scheiben aus dem Weg
    System.out.println("Scheibe " + n + ": " + von + " -> " + nach);
    hanoi(n - 1, hilfe, von, nach);         // 2. kleinere Scheiben nachziehen
}

